create extension if not exists pgcrypto;
create table if not exists profiles (id uuid primary key default gen_random_uuid(), user_id uuid unique, full_name text not null, email text, phone text, country text, city text, role text not null default 'voter', avatar_url text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists categories (id uuid primary key default gen_random_uuid(), slug text unique not null, name text not null, platform_scope text default 'facebook_instagram', description text not null, criteria text not null, icon text, display_order integer default 0, status text default 'active', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists nominees (id uuid primary key default gen_random_uuid(), category_id uuid references categories(id), full_name text not null, display_name text not null, bio text not null, impact_summary text not null, facebook_url text, instagram_url text, website_url text, city text, region text, profile_image_url text, cover_image_url text, submitted_by_name text, submitted_by_email text, verification_status text default 'pending', admin_notes text, vote_count integer default 0, public_slug text unique not null, is_featured boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists votes (id uuid primary key default gen_random_uuid(), nominee_id uuid references nominees(id), category_id uuid references categories(id), voter_email_hash text, voter_user_id uuid, ip_hash text, user_agent_hash text, device_fingerprint_hash text, vote_source text default 'web', fraud_score numeric default 0, status text default 'valid', created_at timestamptz default now());
create table if not exists nominations (id uuid primary key default gen_random_uuid(), category_id uuid references categories(id), nominee_name text not null, nominee_email text, nominee_phone text, nominee_facebook_url text, nominee_instagram_url text, nominee_bio text not null, impact_reason text not null, submitted_by_name text not null, submitted_by_email text not null, consent_confirmed boolean default false, status text default 'pending', admin_notes text, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists sponsors (id uuid primary key default gen_random_uuid(), name text not null, logo_url text, website_url text, tier text default 'partner', description text, display_order integer default 0, status text default 'active', created_at timestamptz default now());
create table if not exists audit_logs (id uuid primary key default gen_random_uuid(), actor_id uuid, action text not null, entity_type text not null, entity_id uuid, metadata jsonb default '{}', created_at timestamptz default now());
create table if not exists settings (key text primary key, value jsonb not null, updated_at timestamptz default now());
create table if not exists data_deletion_requests (id uuid primary key default gen_random_uuid(), full_name text not null, email text not null, request_type text not null, details text not null, created_at timestamptz default now());
create index if not exists idx_nominees_category on nominees(category_id); create index if not exists idx_nominees_status on nominees(verification_status); create index if not exists idx_votes_category on votes(category_id); create index if not exists idx_votes_created on votes(created_at);
alter table profiles enable row level security; alter table categories enable row level security; alter table nominees enable row level security; alter table votes enable row level security; alter table nominations enable row level security; alter table sponsors enable row level security; alter table audit_logs enable row level security; alter table settings enable row level security;
